// Parse Twilio webhook — validation anti-injection
var data = $input.first().json;
var body = data.body || data;

function sanitizePhone(p) { return String(p || '').replace(/[^+0-9]/g, '').substring(0, 16); }
function sanitizeCallSid(s) { return String(s || '').replace(/[^a-zA-Z0-9]/g, '').substring(0, 34); }
function sanitizeText(t) { return String(t || '').replace(/'/g, "''").substring(0, 2000); }

var callSid = sanitizeCallSid(body.CallSid);
var from = sanitizePhone(body.From);
var to = sanitizePhone(body.To);
var callStatus = String(body.CallStatus || '').replace(/[^a-z-]/gi, '').substring(0, 30);
var speechResult = sanitizeText(body.SpeechResult);
var digits = String(body.Digits || '').replace(/[^0-9*#]/g, '').substring(0, 20);
var isCallback = !!speechResult || !!digits;

return [{json: { callSid, from, to, callStatus, speechResult, digits, isCallback }}];

// Router: parse Load All results, build welcome or agent prompt
var parser = $('02. Parse Twilio').first().json;
var isCallback = parser.isCallback;
var callSid = parser.callSid;
var from = parser.from;
var speechResult = parser.speechResult;

// Parse combined query results
var config = {};
var session = null;
var knowledgeRows = [];
var historyRows = [];

try {
  var allRows = $('03. Load All').all();
  for (var i = 0; i < allRows.length; i++) {
    var r = allRows[i].json || allRows[i];
    if (r._type === 'config') {
      config = {
        tenant_id: r.tenant_id || '',
        agent_name: r.nom || "l'assistante",
        company_name: r.prenom || 'TalosPrimes',
        voice_name: r.email || 'Polly.Lea-Neural',
        language: r.telephone || 'fr-FR',
        welcome_message: r.raison_sociale || '',
        max_tokens: parseInt(r.categorie) || 200,
        temperature: parseFloat(r.titre) || 0.3
      };
    } else if (r._type === 'session') {
      session = { nom: r.nom, prenom: r.prenom, email: r.email, telephone: r.telephone, raison_sociale: r.raison_sociale, client_id: r.contenu };
    } else if (r._type === 'kb') {
      knowledgeRows.push({ categorie: r.categorie, titre: r.titre, contenu: r.contenu, reponse_vocale: r.reponse_vocale, mots_cles: r.mots_cles });
    } else if (r._type === 'history') {
      historyRows.push(r.contenu || '');
    }
  }
} catch(e) {}

var tenantId = config.tenant_id || '';
var agentName = config.agent_name || "l'assistante";
var companyName = config.company_name || 'TalosPrimes';
var voiceName = config.voice_name || 'Polly.Lea-Neural';
var language = config.language || 'fr-FR';
var maxTokens = Math.min(config.max_tokens || 200, 300);
var temperature = config.temperature || 0.3;

// ====== WELCOME (first call) ======
if (!isCallback) {
  var welcomeMsg = config.welcome_message || (companyName + ', bonjour ! Comment puis-je vous aider ?');
  function xmlEsc(s) { return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
  welcomeMsg = xmlEsc(welcomeMsg);
  if (!welcomeMsg.trim()) welcomeMsg = 'Bonjour, comment puis-je vous aider ?';

  var twiml = '<?xml version="1.0" encoding="UTF-8"?>\n'
    + '<Response>\n'
    + '  <Say voice="' + voiceName + '" language="' + language + '">' + welcomeMsg + '</Say>\n'
    + '  <Gather input="speech" language="' + language + '" speechTimeout="auto" timeout="8" enhanced="true" bargeIn="true" action="https://n8n.talosprimes.com/webhook/twilio-inbound-voice" method="POST"/>\n'
    + '  <Gather input="speech" language="' + language + '" speechTimeout="auto" timeout="15" enhanced="true" bargeIn="true" action="https://n8n.talosprimes.com/webhook/twilio-inbound-voice" method="POST">\n'
    + '    <Say voice="' + voiceName + '" language="' + language + '">Vous etes toujours la ? N\'hesitez pas a me poser votre question.</Say>\n'
    + '  </Gather>\n'
    + '  <Say voice="' + voiceName + '" language="' + language + '">Je n\'ai pas entendu votre reponse. Au revoir et bonne journee !</Say>\n'
    + '</Response>';

  return [{ json: { isCallback: false, twiml, callSid, from, tenantId, voiceName, language } }];
}

// ====== AGENT PROMPT (callback) ======

// Client info
var clientInfo = '';
if (session && session.nom) {
  clientInfo = 'CLIENT IDENTIFIE: ' + (session.prenom || '') + ' ' + session.nom;
  if (session.email) clientInfo += ' (' + session.email + ')';
  clientInfo += '. Salue-le par son prenom.';
} else {
  clientInfo = 'NOUVEAU NUMERO: ' + from + '. Propose de creer un lead avec create_lead.';
}

// Historique
var exchanges = [];
for (var i = 0; i < historyRows.length; i++) {
  var notes = String(historyRows[i] || '');
  var qM = notes.match(/Q: (.+?) - R: /);
  var rM = notes.match(/R: (.+)$/);
  if (qM && rM) exchanges.push({ q: qM[1].substring(0,150), a: rM[1].substring(0,200) });
}

// KB compact — reponse_vocale prioritaire sur contenu
var faqContext = '';
if (knowledgeRows.length > 0) {
  var byCategorie = {};
  for (var i = 0; i < knowledgeRows.length; i++) {
    var r = knowledgeRows[i];
    if (!r.contenu && !r.reponse_vocale) continue;
    var cat = r.categorie || 'autre';
    if (!byCategorie[cat]) byCategorie[cat] = [];
    var text = r.reponse_vocale || r.contenu || '';
    byCategorie[cat].push((r.titre || '') + ': ' + text);
  }
  var sections = [];
  var catLabels = {info_entreprise:'ENTREPRISE',services:'SERVICES',tarifs:'TARIFS',faq:'FAQ',politiques:'POLITIQUES',actions:'ACTIONS',autre:'AUTRE'};
  var catOrder = ['info_entreprise','services','tarifs','faq','politiques','actions','autre'];
  for (var j = 0; j < catOrder.length; j++) {
    if (byCategorie[catOrder[j]]) {
      sections.push('[' + catLabels[catOrder[j]] + ']\n' + byCategorie[catOrder[j]].join('\n'));
    }
  }
  faqContext = sections.join('\n\n');
}
var maxKB = exchanges.length > 0 ? 6000 : 8000;
if (faqContext.length > maxKB) faqContext = faqContext.substring(0, maxKB) + '\n[...]';

// ====== PROMPT SYSTEME UNIQUE (source unique de verite) ======
var systemPrompt = 'Tu es ' + agentName + ', assistante telephonique de ' + companyName + '.\n'
  + 'Tu es EXPERTE de TOUTE la plateforme TalosPrimes. Tu geres la plateforme a un niveau juste en-dessous du proprietaire.\n'
  + 'Tu es l\'UNIQUE interlocutrice du client. Chaleureuse, naturelle, professionnelle. Vouvoie TOUJOURS.\n\n'
  + clientInfo + '\n\n';

if (faqContext) {
  systemPrompt += '=== BASE DE CONNAISSANCES COMPLETE ===\n' + faqContext + '\n\n';
}

systemPrompt += '=== REGLES ABSOLUES (NON NEGOCIABLES) ===\n'
  + '1. JAMAIS de "un collegue vous rappelle", JAMAIS de delai (24h, 48h), JAMAIS de renvoi vers quelqu\'un d\'autre, JAMAIS de "je fais remonter", JAMAIS de proposition d\'email.\n'
  + '2. Tu es l\'UNIQUE interlocutrice. Pas de collegue, pas d\'equipe, pas de service. TU reponds a TOUT.\n'
  + '3. Tu connais TOUS les modules: facturation, devis, CRM, comptabilite, RH, stock, BTP, marketing digital, projets, conformite, agent IA, etc.\n'
  + '4. Si la question porte sur la plateforme → la reponse EST dans ta base de connaissances. Cherche et reponds avec assurance.\n'
  + '5. Si la question est COMPLETEMENT hors-sujet → recentre poliment sur TalosPrimes.\n'
  + '6. Parle naturellement comme au telephone. Pas de listes, pas de markdown, pas de numeros.\n'
  + '7. UNE question a la fois, puis ecoute.\n'
  + '8. Ne te repete JAMAIS. Ne redis JAMAIS bonjour.\n'
  + '9. Termine TOUJOURS par: "Est-ce que je peux vous aider sur autre chose ?"\n'
  + '10. Nouveau numero inconnu = propose create_lead.\n\n'
  + '=== OUTILS DISPONIBLES ===\n'
  + 'Tu peux appeler ces outils quand necessaire:\n'
  + '- create_lead: enregistrer un prospect (telephone requis)\n'
  + '- create_devis: creer un devis/estimation\n'
  + '- book_rdv: prendre un rendez-vous ou une demo\n'
  + '- get_legal_info: fournir CGV, CGU, RGPD, mentions legales\n'
  + '- get_pricing: detail des tarifs par plan\n'
  + '- check_feature: verifier si un module/fonctionnalite existe\n'
  + '- transfer_human: transferer a un humain (DERNIER recours uniquement)\n\n'
  + '=== ACTIONS INTERDITES ===\n'
  + 'Tu NE PEUX PAS et ne dois JAMAIS tenter de: creer/modifier des factures, supprimer quoi que ce soit, acceder a la comptabilite, modifier les parametres systeme, acceder aux donnees RH.\n'
  + 'Si on te demande ces actions, explique que seul un administrateur peut le faire et propose de prendre un rendez-vous.\n';

// TOOLS (OpenAI functions)
var tools = [
  {type:"function","function":{name:"create_lead",description:"Enregistrer un nouveau prospect dans le CRM TalosPrimes.",parameters:{type:"object",properties:{telephone:{type:"string",description:"Numero de telephone du prospect (requis)"},nom:{type:"string",description:"Nom de famille"},prenom:{type:"string",description:"Prenom"},email:{type:"string",description:"Adresse email"},notes:{type:"string",description:"Notes sur le prospect"}},required:["telephone"]}}},
  {type:"function","function":{name:"create_devis",description:"Creer un devis ou une estimation pour un client.",parameters:{type:"object",properties:{description:{type:"string",description:"Description du devis (requis)"},montant_ht:{type:"number",description:"Montant HT en euros"},plan:{type:"string",description:"Plan concerne: solo, pro, entreprise"}},required:["description"]}}},
  {type:"function","function":{name:"book_rdv",description:"Prendre un rendez-vous ou une demo avec le client.",parameters:{type:"object",properties:{date:{type:"string",description:"Date souhaitee (format libre)"},heure:{type:"string",description:"Heure souhaitee"},objet:{type:"string",description:"Objet du rendez-vous"},telephone:{type:"string",description:"Telephone du client"}},required:["objet"]}}},
  {type:"function","function":{name:"get_legal_info",description:"Fournir les informations legales de TalosPrimes.",parameters:{type:"object",properties:{type:{type:"string",enum:["cgv","cgu","rgpd","mentions_legales"],description:"Type de document legal demande"}},required:["type"]}}},
  {type:"function","function":{name:"get_pricing",description:"Donner le detail des tarifs et plans TalosPrimes.",parameters:{type:"object",properties:{plan:{type:"string",description:"Plan specifique (solo, pro, entreprise) ou vide pour tous"}},required:[]}}},
  {type:"function","function":{name:"check_feature",description:"Verifier si un module ou une fonctionnalite existe sur la plateforme.",parameters:{type:"object",properties:{feature_name:{type:"string",description:"Nom du module ou fonctionnalite a verifier"}},required:["feature_name"]}}},
  {type:"function","function":{name:"transfer_human",description:"Transferer l'appel a un humain. UNIQUEMENT en dernier recours si le client insiste et que tu ne peux vraiment pas l'aider.",parameters:{type:"object",properties:{raison:{type:"string",description:"Raison du transfert"},urgence:{type:"string",enum:["normale","urgente"],description:"Niveau d'urgence"}},required:["raison"]}}}
];

// Messages
var messages = [{role:"system",content:systemPrompt}];
for (var h = 0; h < exchanges.length && h < 2; h++) {
  messages.push({role:"user",content:exchanges[h].q});
  messages.push({role:"assistant",content:exchanges[h].a});
}
messages.push({role:"user",content:speechResult});

return [{ json: {
  isCallback: true,
  messages: JSON.stringify(messages),
  tools: JSON.stringify(tools),
  maxTokens: maxTokens,
  temperature: temperature,
  tenantId: tenantId,
  callSid: callSid,
  from: from,
  speechResult: speechResult,
  voiceName: voiceName,
  language: language,
  agentName: agentName,
  companyName: companyName
}}];

// Parse OpenAI response — detect tool calls
var openaiResponse = $input.first().json;
var prev = $('04. Router').first().json;

if (!openaiResponse || !openaiResponse.choices || !openaiResponse.choices[0]) {
  return [{ json: {
    hasToolCall: false,
    aiReply: "Excusez-moi, j'ai eu un petit souci technique. Pouvez-vous repeter votre demande ?",
    callSid: prev.callSid || '', from: prev.from || '', speechResult: prev.speechResult || '',
    tenantId: prev.tenantId || '', voiceName: prev.voiceName || 'Polly.Lea-Neural',
    language: prev.language || 'fr-FR'
  }}];
}

var message = openaiResponse.choices[0].message;
var finishReason = openaiResponse.choices[0].finish_reason;

// === VALIDATION HELPERS ===
var PHONE_RE = /^\+?[0-9]{6,15}$/;
var EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
function sanitizePhone(p) { return String(p || '').replace(/[^+0-9]/g, '').substring(0, 16); }
function safe(s, maxLen) { return String(s || '').substring(0, maxLen || 500); }
function interpolateSQL(q, p) {
  return q.replace(/\$(\d+)/g, function(_, i) {
    var v = p[parseInt(i) - 1];
    if (v === null || v === undefined) return 'NULL';
    if (typeof v === 'number') return String(v);
    return "'" + String(v).replace(/'/g, "''") + "'";
  });
}

if (finishReason === 'tool_calls' && message?.tool_calls?.length > 0) {
  var toolCall = message.tool_calls[0];
  var toolName = toolCall.function.name;
  var toolArgs = JSON.parse(toolCall.function.arguments || '{}');
  var toolCallId = toolCall.id;
  var tenantId = prev.tenantId || '';

  var ALLOWED_TOOLS = ['create_lead', 'create_devis', 'book_rdv', 'get_legal_info', 'get_pricing', 'check_feature', 'transfer_human'];
  if (!ALLOWED_TOOLS.includes(toolName)) {
    return [{ json: {
      hasToolCall: false,
      aiReply: "Cette action n'est pas autorisee. Est-ce que je peux vous aider autrement ?",
      callSid: prev.callSid, from: prev.from, speechResult: prev.speechResult,
      tenantId: tenantId, voiceName: prev.voiceName, language: prev.language
    }}];
  }

  var sqlQuery = '';
  var sqlParams = [];

  if (toolName === 'create_lead') {
    var tel = sanitizePhone(toolArgs.telephone || prev.from);
    var nom = safe(toolArgs.nom, 100);
    var prenom = safe(toolArgs.prenom, 100);
    var email = toolArgs.email && EMAIL_RE.test(toolArgs.email) ? safe(toolArgs.email, 255) : '';
    var notes = safe(toolArgs.notes, 500);
    if (!tel) tel = sanitizePhone(prev.from);
    sqlQuery = `INSERT INTO leads (id, tenant_id, nom, prenom, email, telephone, source, statut, notes, created_at, updated_at)
      SELECT gen_random_uuid(), COALESCE(NULLIF($1, '')::uuid, (SELECT id FROM tenants LIMIT 1)), $2, $3, $4, $5, 'telephone_ia', 'nouveau', $6, NOW(), NOW()
      WHERE NOT EXISTS (SELECT 1 FROM leads WHERE telephone LIKE '%' || RIGHT($5, 9) || '%' AND statut != 'abandonne')
      RETURNING id, nom, prenom, telephone, 'Lead cree avec succes' as message`;
    sqlParams = [tenantId, nom, prenom, email, tel, notes];
  }
  else if (toolName === 'create_devis') {
    var ht = parseFloat(toolArgs.montant_ht) || 0;
    var tva = 20;
    var ttc = ht > 0 ? ht * 1.2 : 0;
    var desc = safe(toolArgs.description, 500);
    var plan = safe(toolArgs.plan, 50);
    var numDevis = 'DEV-' + Date.now();
    sqlQuery = `INSERT INTO devis (id, tenant_id, numero_devis, date_devis, date_validite, montant_ht, montant_ttc, tva_taux, description, statut, created_at, updated_at)
      VALUES (gen_random_uuid(), COALESCE(NULLIF($1, '')::uuid, (SELECT id FROM tenants LIMIT 1)),
        $2, NOW(), NOW() + INTERVAL '30 days', $3, $4, $5, $6, 'brouillon', NOW(), NOW())
      RETURNING id, numero_devis, montant_ht, montant_ttc, statut, 'Devis cree' as message`;
    sqlParams = [tenantId, numDevis, ht, parseFloat(ttc.toFixed(2)), tva, desc + (plan ? ' (Plan: ' + plan + ')' : '')];
  }
  else if (toolName === 'book_rdv') {
    var objet = safe(toolArgs.objet, 200);
    var date = safe(toolArgs.date, 50);
    var heure = safe(toolArgs.heure, 20);
    var tel = sanitizePhone(toolArgs.telephone || prev.from);
    sqlQuery = `INSERT INTO leads (id, tenant_id, nom, telephone, source, statut, notes, created_at, updated_at)
      SELECT gen_random_uuid(), COALESCE(NULLIF($1, '')::uuid, (SELECT id FROM tenants LIMIT 1)),
        'RDV', $2, 'telephone_ia', 'contacte',
        'RDV demande: ' || $3 || COALESCE(' le ' || NULLIF($4, ''), '') || COALESCE(' a ' || NULLIF($5, ''), ''),
        NOW(), NOW()
      RETURNING id, notes as message, telephone`;
    sqlParams = [tenantId, tel, objet, date, heure];
  }
  else if (toolName === 'get_legal_info') {
    var type = safe(toolArgs.type, 30);
    sqlQuery = `SELECT titre, reponse_vocale, contenu FROM agent_knowledge_entries
      WHERE tenant_id = COALESCE(NULLIF($1, '')::uuid, (SELECT id FROM tenants LIMIT 1))
      AND actif = true AND (LOWER(titre) LIKE '%' || $2 || '%' OR LOWER(categorie) LIKE '%' || $2 || '%' OR LOWER(mots_cles) LIKE '%' || $2 || '%')
      ORDER BY CASE WHEN LOWER(titre) LIKE '%' || $2 || '%' THEN 1 ELSE 2 END
      LIMIT 3`;
    sqlParams = [tenantId, type];
  }
  else if (toolName === 'get_pricing') {
    var plan = safe(toolArgs.plan || '', 50).toLowerCase();
    sqlQuery = `SELECT titre, reponse_vocale, contenu FROM agent_knowledge_entries
      WHERE tenant_id = COALESCE(NULLIF($1, '')::uuid, (SELECT id FROM tenants LIMIT 1))
      AND actif = true AND categorie = 'tarifs'
      ` + (plan ? "AND (LOWER(titre) LIKE '%" + plan.replace(/'/g,"''") + "%' OR LOWER(contenu) LIKE '%" + plan.replace(/'/g,"''") + "%')" : "") + `
      ORDER BY ordre, created_at LIMIT 5`;
    sqlParams = [tenantId];
  }
  else if (toolName === 'check_feature') {
    var feat = safe(toolArgs.feature_name, 100).toLowerCase();
    sqlQuery = `SELECT titre, reponse_vocale, contenu, categorie FROM agent_knowledge_entries
      WHERE tenant_id = COALESCE(NULLIF($1, '')::uuid, (SELECT id FROM tenants LIMIT 1))
      AND actif = true AND (LOWER(titre) LIKE '%' || $2 || '%' OR LOWER(contenu) LIKE '%' || $2 || '%' OR LOWER(mots_cles) LIKE '%' || $2 || '%')
      ORDER BY CASE WHEN LOWER(titre) LIKE '%' || $2 || '%' THEN 1 WHEN LOWER(mots_cles) LIKE '%' || $2 || '%' THEN 2 ELSE 3 END
      LIMIT 3`;
    sqlParams = [tenantId, feat];
  }
  else if (toolName === 'transfer_human') {
    sqlQuery = `SELECT 'transfer_requested' as status, $1 as raison, $2 as urgence`;
    sqlParams = [safe(toolArgs.raison, 200), safe(toolArgs.urgence || 'normale', 20)];
  }

  var finalSQL = interpolateSQL(sqlQuery, sqlParams);
  var msgsCopy = JSON.parse(prev.messages);
  msgsCopy.push(message);

  return [{ json: {
    hasToolCall: true,
    toolCallId: toolCallId,
    toolName: toolName,
    toolArgs: JSON.stringify(toolArgs),
    sqlQuery: finalSQL,
    messages: JSON.stringify(msgsCopy),
    tools: prev.tools,
    callSid: prev.callSid, from: prev.from, speechResult: prev.speechResult,
    tenantId: tenantId, voiceName: prev.voiceName, language: prev.language
  }}];
}

// No tool call — direct response
var aiReply = message?.content || "Excusez-moi, je n'ai pas pu traiter votre demande. Pouvez-vous reformuler ?";

return [{ json: {
  hasToolCall: false,
  aiReply: aiReply,
  callSid: prev.callSid, from: prev.from, speechResult: prev.speechResult,
  tenantId: prev.tenantId, voiceName: prev.voiceName, language: prev.language
}}];

// Build 2nd OpenAI call with tool result
var prev = $('08. Process Response').first().json;
var toolResult = $input.first().json;
var messages = JSON.parse(prev.messages);

messages.push({
  role: 'tool',
  tool_call_id: prev.toolCallId,
  content: JSON.stringify(toolResult)
});

return [{ json: {
  jsonBody: JSON.stringify({
    model: 'gpt-4o-mini',
    messages: messages,
    max_tokens: 200,
    temperature: 0.3
  }),
  callSid: prev.callSid, from: prev.from, speechResult: prev.speechResult,
  tenantId: prev.tenantId, voiceName: prev.voiceName, language: prev.language,
  toolUsed: prev.toolName
}}];

// Extract final reply from tool-enhanced OpenAI response
var openai = $input.first().json;
var prev = $('11. Build Tool Body').first().json;
var aiReply = '';

try {
  if (openai && openai.choices && openai.choices[0]) {
    aiReply = openai.choices[0].message.content || '';
  }
} catch(e) {}

if (!aiReply) aiReply = "J'ai bien enregistre votre demande. Est-ce que je peux vous aider sur autre chose ?";

return [{ json: {
  hasToolCall: false,
  aiReply: aiReply,
  callSid: prev.callSid, from: prev.from, speechResult: prev.speechResult,
  tenantId: prev.tenantId, voiceName: prev.voiceName, language: prev.language,
  toolUsed: prev.toolUsed
}}];

// Build TwiML response from AI reply
var data = $input.first().json;
var aiReply = data.aiReply || "Excusez-moi, je n'ai pas pu traiter votre demande.";
var voice = data.voiceName || 'Polly.Lea-Neural';
var lang = data.language || 'fr-FR';
var callbackUrl = 'https://n8n.talosprimes.com/webhook/twilio-inbound-voice';

// Clean for TwiML
aiReply = aiReply
  .replace(/\*\*/g, '')
  .replace(/\*/g, '')
  .replace(/#/g, '')
  .replace(/\n/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

// XML escape
function xmlEsc(s) {
  return String(s||'')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;');
}
aiReply = xmlEsc(aiReply);

// Truncate for voice (max ~500 chars for natural speech)
if (aiReply.length > 500) {
  aiReply = aiReply.substring(0, 497) + '...';
}

var twiml = '<?xml version="1.0" encoding="UTF-8"?>\n'
  + '<Response>\n'
  + '  <Say voice="' + voice + '" language="' + lang + '">' + aiReply + '</Say>\n'
  + '  <Gather input="speech" language="' + lang + '" speechTimeout="auto" timeout="8" enhanced="true" bargeIn="true" action="' + callbackUrl + '" method="POST"/>\n'
  + '  <Gather input="speech" language="' + lang + '" speechTimeout="auto" timeout="15" enhanced="true" bargeIn="true" action="' + callbackUrl + '" method="POST">\n'
  + '    <Say voice="' + voice + '" language="' + lang + '">Avez-vous une autre question ?</Say>\n'
  + '  </Gather>\n'
  + '  <Say voice="' + voice + '" language="' + lang + '">Merci de votre appel. Bonne journee !</Say>\n'
  + '</Response>';

return [{ json: {
  twiml: twiml,
  callSid: data.callSid || '',
  from: data.from || '',
  tenantId: data.tenantId || '',
  aiReply: data.aiReply || '',
  speechResult: data.speechResult || '',
  toolUsed: data.toolUsed || ''
}}];

